            cin >> c;

            initial[i] = (c == 'B');

        }

        for(int i=0; i<n; ++i){

            char c;

            cin >> c;

            final[i] = (c == 'B');

        }



        vector<vector<int> > memo(1<<n, vector<int>(n, INF));

